} from "@/components/ui/table";
import { useOnlineStatus } from "@/hooks/use-offline-data";
import { deleteCustomer } from "@/lib/actions/customer.actions";
import { getAllCustomers } from "@/offline/offline-service";
import { CloudOff, Eye, RefreshCw, Search, Trash2, X } from "lucide-react";
import { useTranslations } from "next-intl";
import { useRouter } from "next/navigation";
import { useCallback, useEffect, useRef, useState, useTransition } from "react";
import { useDebounce } from "use-debounce";
import { toast } from "sonner";

interface Customer {
    id: string;
    name: string;
    phone: string;
    cnic: string | null;
    address: string | null;
    outstandingAmount: number;
    paidAmount: number;
    isActive: boolean;
}

interface ServerCustomer {
    id: string;
    name: string;
    phone: string;
    cnic: string | null;
    address: string | null;
    outstandingAmount: string | number;
    paidAmount: string | number;
    isActive: boolean;
}

interface CustomersPageResponse {
    data: ServerCustomer[];
    nextCursor: string | null;
    total: number;
}

interface CustomerPage {
    customers: Customer[];
    nextCursor: string | null;
    total: number;
}

function parseAmount(value: string | number | null | undefined) {
    if (typeof value === "number") return value;
    const parsed = Number.parseFloat(value ?? "0");
    return Number.isFinite(parsed) ? parsed : 0;
}

function mapServerCustomer(customer: ServerCustomer): Customer {
    return {
        id: customer.id,
        name: customer.name,
        phone: customer.phone,
        cnic: customer.cnic,
        address: customer.address || null,
        outstandingAmount: parseAmount(customer.outstandingAmount),
        paidAmount: parseAmount(customer.paidAmount),
        isActive: customer.isActive,
    };
}

function filterAndSortCustomers(customers: Customer[], search: string, outstandingOnly: boolean) {
    const query = search.trim().toLowerCase();

    return customers
        .filter((customer) => {
            if (!customer.isActive) return false;
            if (outstandingOnly && customer.outstandingAmount <= 0) return false;
            if (!query) return true;

            return (
                customer.name.toLowerCase().includes(query) ||
                customer.phone.toLowerCase().includes(query) ||
                (customer.cnic?.toLowerCase().includes(query) ?? false)
            );
        })
        .sort((a, b) => {
            const nameCompare = a.name.toLowerCase().localeCompare(b.name.toLowerCase());
            return nameCompare || a.id.localeCompare(b.id);
        });
}

async function fetchCustomersOffline(search: string, outstandingOnly: boolean): Promise<CustomerPage> {
    const offlineCustomers = await getAllCustomers();
    const mappedCustomers = offlineCustomers.map((customer) => ({
        id: customer.id,
        name: customer.name,
        phone: customer.phone,
        cnic: customer.cnic,
        address: customer.address || null,
        outstandingAmount: customer.outstandingAmount,
        paidAmount: customer.paidAmount,
        isActive: customer.isActive,
    }));
    const customers = filterAndSortCustomers(mappedCustomers, search, outstandingOnly);

    return {
        customers,
        nextCursor: null,
        total: customers.length,
    };
}

