}

export function CustomersClient() {
    const router = useRouter();
    const isOnline = useOnlineStatus();
    const t = useTranslations("customers");
    const tc = useTranslations("common");
    const [isPending, startTransition] = useTransition();

    const [deleteTarget, setDeleteTarget] = useState<Customer | null>(null);
    const [searchQuery, setSearchQuery] = useState("");
    const [outstandingOnly, setOutstandingOnly] = useState(false);
    const [debouncedSearch] = useDebounce(searchQuery, 350);

    const [customers, setCustomers] = useState<Customer[]>([]);
    const [isSearchLoading, setIsSearchLoading] = useState(true);
    const [isLoadingMore, setIsLoadingMore] = useState(false);
    const [isOffline, setIsOffline] = useState(false);
    const [nextCursor, setNextCursor] = useState<string | null>(null);
    const [totalItems, setTotalItems] = useState(0);

    const sentinelRef = useRef<HTMLDivElement>(null);
    const isFirstLoad = useRef(true);
    const hasBooted = useRef(false);
    const requestIdRef = useRef(0);
    const loadingCursorRef = useRef<string | null>(null);
    const previousOnlineRef = useRef(isOnline);

    const fetchServerPage = useCallback(async (
        search: string,
        outstanding: boolean,
        cursor: string | null
    ): Promise<CustomerPage> => {
        const params = new URLSearchParams();
        const trimmedSearch = search.trim();

        if (trimmedSearch) params.set("q", trimmedSearch);
        if (cursor) params.set("cursor", cursor);
        if (outstanding) params.set("outstanding", "true");
        params.set("_t", Date.now().toString());

        const res = await fetch(`/api/customers?${params.toString()}`, { cache: "no-store" });
        if (!res.ok) throw new Error("Failed to fetch customers");

        const json = await res.json() as CustomersPageResponse;

        return {
            customers: (json.data || []).map(mapServerCustomer),
            nextCursor: json.nextCursor,
            total: json.total,
        };
    }, []);

    const loadFirstPage = useCallback(async (search: string, outstanding: boolean, silent = false) => {
        const requestId = requestIdRef.current + 1;
        requestIdRef.current = requestId;
        loadingCursorRef.current = null;

        setCustomers([]);
        setNextCursor(null);
        setTotalItems(0);
        setIsLoadingMore(false);
        if (!silent) setIsSearchLoading(true);

        try {
            const page = isOnline
                ? await fetchServerPage(search, outstanding, null).then((result) => {
                    setIsOffline(false);
                    return result;
                }).catch(async (error: unknown) => {
                    console.warn("Server fetch failed, falling back to offline customers:", error);
                    setIsOffline(true);
                    return fetchCustomersOffline(search, outstanding);
                })
                : await fetchCustomersOffline(search, outstanding).then((result) => {
                    setIsOffline(true);
                    return result;
                });

            if (requestIdRef.current !== requestId) return;

            setCustomers(page.customers);
            setNextCursor(page.nextCursor);
            setTotalItems(page.total);
        } catch (error) {
            console.error("Failed to load customers:", error);
            if (requestIdRef.current === requestId) {
                setIsOffline(!isOnline);
            }
        } finally {
            if (requestIdRef.current === requestId) {
                setIsSearchLoading(false);
            }
        }
    }, [fetchServerPage, isOnline]);

    useEffect(() => {
        if (hasBooted.current) return;
        hasBooted.current = true;

        loadFirstPage("", false).finally(() => {
            isFirstLoad.current = false;
        });
    }, [loadFirstPage]);

    const prevSearch = useRef(debouncedSearch);
    const prevOutstanding = useRef(outstandingOnly);

    useEffect(() => {
        if (isFirstLoad.current) return;
        if (prevSearch.current === debouncedSearch && prevOutstanding.current === outstandingOnly) return;

        prevSearch.current = debouncedSearch;
        prevOutstanding.current = outstandingOnly;
        loadFirstPage(debouncedSearch, outstandingOnly);
