        if (!previousOnlineRef.current && isOnline) {
            loadFirstPage(debouncedSearch, outstandingOnly, true);
        }

        previousOnlineRef.current = isOnline;
    }, [debouncedSearch, isOnline, loadFirstPage, outstandingOnly]);

    const loadMore = useCallback(async () => {
        const cursor = nextCursor;
        if (isLoadingMore || !cursor || isOffline || isSearchLoading || loadingCursorRef.current === cursor) return;

        const requestId = requestIdRef.current;
        loadingCursorRef.current = cursor;
        setIsLoadingMore(true);

        try {
            const page = await fetchServerPage(debouncedSearch, outstandingOnly, cursor);
            if (requestIdRef.current !== requestId) return;

            setCustomers((prev) => {
                const existingIds = new Set(prev.map((customer) => customer.id));
                const newCustomers = page.customers.filter((customer) => !existingIds.has(customer.id));
                return [...prev, ...newCustomers];
            });
            setNextCursor(page.nextCursor);
            setTotalItems(page.total);
        } catch (error) {
            console.error("Failed to load more customers:", error);
        } finally {
            if (loadingCursorRef.current === cursor) {
                loadingCursorRef.current = null;
                setIsLoadingMore(false);
            }
        }
    }, [debouncedSearch, fetchServerPage, isLoadingMore, isOffline, isSearchLoading, nextCursor, outstandingOnly]);

    useEffect(() => {
        const sentinel = sentinelRef.current;
        if (!sentinel) return;

        const observer = new IntersectionObserver(
            (entries) => {
                if (entries[0].isIntersecting) {
                    loadMore();
                }
            },
            { threshold: 0.1 }
        );

        observer.observe(sentinel);
        return () => observer.disconnect();
    }, [loadMore]);

    const refetch = useCallback(() => {
        return loadFirstPage(debouncedSearch, outstandingOnly);
    }, [debouncedSearch, loadFirstPage, outstandingOnly]);

    const clearFilters = () => {
        setSearchQuery("");
        setOutstandingOnly(false);
    };

    const handleDeactivate = () => {
        if (!deleteTarget) return;
        startTransition(async () => {
            const result = await deleteCustomer(deleteTarget.id);
            if (result.success) {
                toast.success(t("customerDeactivated"));
                router.refresh();
                refetch();
            } else {
                toast.error(result.error || "Failed to deactivate customer");
            }
            setDeleteTarget(null);
        });
    };

    const hasActiveFilters = Boolean(searchQuery.trim() || outstandingOnly);
    const hasMore = Boolean(nextCursor);

    return (
        <>
            <div className="space-y-6">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <h2 className="text-3xl font-bold tracking-tight">{t("title")}</h2>
                        {isOffline && (
                            <Badge variant="outline" className="text-yellow-600 border-yellow-600">
                                <CloudOff className="h-3 w-3 mr-1" />
                                {tc("offlineData")}
                            </Badge>
                        )}
                    </div>
                    <div className="flex items-center gap-2">
                        <Button variant="outline" size="icon" onClick={refetch} disabled={!isOnline}>
                            <RefreshCw className="h-4 w-4" />
                        </Button>
                        {!isOffline && <AddCustomerDialog />}
                    </div>
                </div>

                <Card>
                    <CardHeader className="gap-4">
                        <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                            <CardTitle>{t("customerList")}</CardTitle>
                            {!isSearchLoading && (
                                <span className="text-sm text-muted-foreground">
                                    {customers.length}{hasMore ? "+" : ""} / {totalItems}
                                </span>
                            )}
                        </div>
                        <div className="flex flex-col sm:flex-row gap-3 sm:items-center">
                            <div className="relative w-full sm:max-w-sm">
                                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                                <Input
                                    placeholder={`${tc("search")}...`}
                                    value={searchQuery}
                                    onChange={(event) => setSearchQuery(event.target.value)}
                                    className="pl-9"
                                />
                            </div>
                            <div className="flex h-9 items-center gap-2 rounded-md border px-3">
                                <Switch
                                    id="outstanding-customers"
                                    checked={outstandingOnly}
                                    onCheckedChange={setOutstandingOnly}
                                />
                                <label htmlFor="outstanding-customers" className="text-sm">
                                    {t("outstandingAmount")}
                                </label>
                            </div>
                            {hasActiveFilters && (
                                <Button variant="ghost" size="icon" onClick={clearFilters} title={tc("clearFilters")}>
                                    <X className="h-4 w-4" />
                                </Button>
                            )}
                        </div>
                    </CardHeader>
                    <CardContent className="space-y-3">
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>{tc("name")}</TableHead>
                                    <TableHead>{t("phone")}</TableHead>
                                    <TableHead>{t("cnic")}</TableHead>
                                    <TableHead className="text-right">{t("paidAmount")}</TableHead>
                                    <TableHead className="text-right">{t("outstandingAmount")}</TableHead>
                                    <TableHead className="text-right">{tc("actions")}</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {isSearchLoading ? (
                                    [...Array(6)].map((_, i) => <CustomersSkeletonRow key={i} />)
                                ) : customers.length === 0 ? (
                                    <TableRow>
                                        <TableCell colSpan={6} className="text-center h-24">
                                            {t("noCustomersFound")}
                                        </TableCell>
                                    </TableRow>
                                ) : (
                                    <>
                                        {customers.map((customer) => (
                                            <TableRow key={customer.id}>
                                                <TableCell className="font-medium">{customer.name}</TableCell>
                                                <TableCell>{customer.phone}</TableCell>
                                                <TableCell>{customer.cnic || '—'}</TableCell>
                                                <TableCell className="text-right text-green-600">
                                                    Rs. {customer.paidAmount.toLocaleString()}
                                                </TableCell>
                                                <TableCell className={`text-right ${customer.outstandingAmount > 0 ? "text-red-500 font-bold" : "text-green-600"}`}>
                                                    Rs. {customer.outstandingAmount.toLocaleString()}
                                                </TableCell>
                                                <TableCell className="text-right">
                                                    <div className="flex items-center justify-end gap-1">
                                                        <Button
                                                            variant="ghost"
                                                            size="icon"
                                                            title={t("customerDetails")}
                                                            onClick={() => router.push(`/customers/${customer.id}`)}
                                                        >
                                                            <Eye className="h-4 w-4" />
                                                        </Button>
                                                        {!isOffline && (
                                                            <>
                                                                <EditCustomerDialog customer={customer} />
                                                                <Button
                                                                    variant="ghost"
                                                                    size="icon"
                                                                    className="text-destructive hover:text-destructive"
                                                                    title={t("deactivateCustomer")}
                                                                    onClick={() => setDeleteTarget(customer)}
                                                                >
                                                                    <Trash2 className="h-4 w-4" />
                                                                </Button>
                                                            </>
                                                        )}
                                                    </div>
                                                </TableCell>
                                            </TableRow>
                                        ))}
                                        {isLoadingMore && [...Array(4)].map((_, i) => <CustomersSkeletonRow key={`more-${i}`} />)}
                                    </>
                                )}
                            </TableBody>
                        </Table>
                        <div ref={sentinelRef} className="h-4" />
                        {!hasMore && !isSearchLoading && customers.length > 0 && (
                            <p className="text-center text-xs text-muted-foreground pb-2">
                                {tc("showing")} {customers.length} {tc("of")} {totalItems} {tc("entries")}
                            </p>
                        )}
                    </CardContent>
                </Card>
            </div>

            <AlertDialog
                open={!!deleteTarget}
                onOpenChange={(val) => {
                    if (!val) setDeleteTarget(null);
                }}
            >
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>{t("deactivateCustomer")}</AlertDialogTitle>
                        <AlertDialogDescription>
                            {t("confirmDeactivateCustomer", { name: deleteTarget?.name || "" })}
