import { db } from "@/db";
import { customers } from "@/db/schema";
import { and, asc, count, eq, gt, ilike, or, sql } from "drizzle-orm";
import type { SQL } from "drizzle-orm";
import { NextRequest, NextResponse } from "next/server";

const CUSTOMER_PAGE_SIZE = 30;

interface CustomerCursor {
    name: string;
    id: string;
}

function encodeCursor(customer: { name: string; id: string }) {
    return Buffer.from(
        JSON.stringify({
            name: customer.name.toLowerCase(),
            id: customer.id,
        } satisfies CustomerCursor)
    ).toString("base64url");
}

function decodeCursor(cursor: string): CustomerCursor | null {
    try {
        const parsed = JSON.parse(Buffer.from(cursor, "base64url").toString("utf8")) as Partial<CustomerCursor>;
        if (typeof parsed.name !== "string" || typeof parsed.id !== "string") {
            return null;
        }

        return {
            name: parsed.name,
            id: parsed.id,
        };
    } catch {
        return null;
    }
}

export async function GET(req: NextRequest) {
    const { searchParams } = new URL(req.url);
    const query = searchParams.get("q")?.trim() ?? "";
    const cursorParam = searchParams.get("cursor");
    const outstandingOnly = searchParams.get("outstanding") === "true";

    try {
        const baseFilters: SQL[] = [eq(customers.isActive, true)];

        if (query) {
            const searchPattern = `%${query}%`;
            const searchFilter = or(
                ilike(customers.name, searchPattern),
                ilike(customers.phone, searchPattern),
                ilike(customers.cnic, searchPattern)
            );

            if (searchFilter) {
                baseFilters.push(searchFilter);
            }
        }

        if (outstandingOnly) {
            baseFilters.push(gt(customers.outstandingAmount, "0"));
        }

        const cursor = cursorParam ? decodeCursor(cursorParam) : null;
        if (cursorParam && !cursor) {
            return NextResponse.json({ error: "Invalid customer cursor" }, { status: 400 });
        }

        const pageFilters = [...baseFilters];
        if (cursor) {
            const cursorFilter = or(
                sql`lower(${customers.name}) > ${cursor.name}`,
                and(
                    sql`lower(${customers.name}) = ${cursor.name}`,
                    gt(customers.id, cursor.id)
                )
            );

            if (cursorFilter) {
                pageFilters.push(cursorFilter);
            }
        }

        const whereClause = and(...baseFilters);
        const pageWhereClause = and(...pageFilters);

        const [rows, totalRows] = await Promise.all([
            db
                .select()
                .from(customers)
                .where(pageWhereClause)
                .orderBy(asc(sql`lower(${customers.name})`), asc(customers.id))
                .limit(CUSTOMER_PAGE_SIZE + 1),
            db.select({ total: count() }).from(customers).where(whereClause),
        ]);

        const pageData = rows.slice(0, CUSTOMER_PAGE_SIZE);
        const lastCustomer = pageData[pageData.length - 1];
        const nextCursor = rows.length > CUSTOMER_PAGE_SIZE && lastCustomer
            ? encodeCursor({ name: lastCustomer.name, id: lastCustomer.id })
            : null;

        return NextResponse.json({
            data: pageData,
            nextCursor,
            total: totalRows[0]?.total ?? 0,
        });
    } catch (error) {
        return NextResponse.json({ error: "Failed to fetch customers" }, { status: 500 });
    }
}

